-- دفعة رابعة وأخيرة من الشبهات — تُكمل الحد الأدنى الأصلي (١٥ شبهة)
-- من المواضيع الآمنة المتبقية في القائمة الأصلية: حفظ القرآن
-- والقراءات، ميراث المرأة، مشكلة الشر والألم، الإسلام والتطور
-- العلمي، معنى الجهاد (عام لا فقه تفصيلي)، تصور العنف في الإسلام.
-- 9 → 15 شبهة.
-- الشبهات الأكثر حساسية (سن عائشة رضي الله عنها، الرق في التاريخ
-- الإسلامي، حكم الردة الفقهي التفصيلي، فقه الجهاد التفصيلي/العسكري)
-- تبقى مؤجَّلة عمدًا لعالم شرعي متخصص — قرار سلامة محتوى ثابت لا
-- يتغيّر بتغيّر الصلاحيات الإدارية الممنوحة.
-- عدد الأعمدة لكل سطر = ١٦ بالضبط (تحقّق يدوي دقيق بعد خطأ سابق مشابه):
-- category_id, slug, title, complexity_level, shubha_text, why_spread,
-- short_answer, detailed_refutation, assumption_correction,
-- historical_linguistic_context, evidences, sources,
-- objections_and_responses, conclusion, status, is_approved.
INSERT INTO dawah_shubuhat (category_id, slug, title, complexity_level, shubha_text, why_spread, short_answer, detailed_refutation, assumption_correction, historical_linguistic_context, evidences, sources, objections_and_responses, conclusion, status, is_approved) VALUES

((SELECT id FROM dawah_categories WHERE slug='quran'), 'quran-preservation-and-qiraat',
'ألا يدل وجود "قراءات" متعددة للقرآن على أن النص غير محفوظ فعلًا؟', 'intermediate',
'"سمعت أن هناك قراءات مختلفة للقرآن، أليس هذا دليلًا على أن النص تغيّر أو أن هناك نسخًا متضاربة منه؟"',
'تنتشر هذه الشبهة لدى من يسمع مصطلح "القراءات" لأول مرة فيظنه يعني اختلاف نسخ متضاربة، بدل فهمه الصحيح كأوجه نطق متواترة موثَّقة كلها عن النبي ﷺ نفسه.',
'"القراءات" ليست نسخًا متضاربة أو أخطاء نقل، بل أوجه نطق متعددة متواترة للنص القرآني نفسه، نزل بها الوحي أصلًا للتيسير على قبائل العرب المختلفة لهجاتها، ونُقلت كلها بسند متصل موثَّق إلى النبي ﷺ.',
'ثبت في السنة أن النبي ﷺ نفسه أُذِن له أن يُقرَأ القرآن "على سبعة أحرف" تيسيرًا على العرب المختلفين في لهجاتهم، وهذا أصل شرعي للتعدد لا عيب فيه أو دليل تحريف. القراءات المتواترة المعروفة اليوم (كقراءة حفص عن عاصم، الأكثر انتشارًا، وقراءة ورش عن نافع المنتشرة في شمال أفريقيا، وغيرها من القراءات العشر المتواترة) تختلف غالبًا في تفصيلات نطقية صوتية دقيقة جدًا (كإمالة حرف أو مدّه أو تفخيمه) لا في المعنى الجوهري للآيات أو أحكامها، وكلها منقولة بسند متصل متواتر (رواة كُثر في كل طبقة يستحيل تواطؤهم على كذب) يعود للنبي ﷺ مباشرة، موثَّق في علم القراءات المتخصص الذي يُدرَّس ويُسنَد إجازة كأي علم نقلي دقيق آخر. هذا يختلف جذريًا عن مفهوم "نسخ متضاربة" في نصوص أخرى تعرّضت لتعدد ترجمات أو مخطوطات مختلفة المصدر دون سند تحقق مماثل؛ القراءات القرآنية كلها ترجع لمصدر واحد موثَّق (النبي ﷺ) بطرق نقل متعددة موثَّقة، لا مصادر متعددة متضاربة.',
'مغالطة شائعة: الخلط بين "تعدد القراءات المتواترة الموثَّقة" و"اختلاف النسخ المتضارب"؛ الأول تنوع مُقَرّ ومسنَد شرعًا، والثاني عيب نقل حقيقي غير موجود في تاريخ حفظ القرآن.',
'علم القراءات علم إسلامي متخصص قديم جدًا، له أسانيد إجازة موثَّقة تُنقَل من معلّم لتلميذ عبر قرون، تمامًا كعلم الحديث في تدقيقه وضبطه، وليس اختراعًا حديثًا أو ثغرة أُكتُشِفت مؤخرًا.',
'[{"type":"hadith","ref":"متفق عليه، من حديث عمر بن الخطاب رضي الله عنه","grading":"صحيح متفق عليه","text":"إِنَّ هَذَا الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ فَاقْرَءُوا مَا تَيَسَّرَ مِنْهُ"}]'::jsonb,
'[]'::jsonb,
'[{"objection":"لماذا لا نستخدم قراءة واحدة فقط لتجنّب اللبس؟","response":"القراءات المتعددة إثراء موثَّق لا لبس فيه لمن فهم طبيعتها؛ المصحف المطبوع اليوم غالبًا برواية حفص عن عاصم كمعيار شائع للطباعة، لكن هذا لا يلغي صحة القراءات الأخرى المتواترة ولا يجعلها نسخًا متضاربة."}]'::jsonb,
'تعدد القراءات القرآنية ظاهرة موثَّقة بسند متواتر ترجع كلها للنبي ﷺ، ودليل ثراء نقلي دقيق لا ثغرة في حفظ النص كما يُظَن أحيانًا خطأً.',
'draft', false),

((SELECT id FROM dawah_categories WHERE slug='women-family'), 'womens-inheritance-explained',
'لماذا يرث الرجل ضعف المرأة في الإسلام؟ أليس هذا ظلمًا واضحًا؟', 'intermediate',
'"القرآن يقول صراحة إن للذكر مثل حظ الأنثيين في الميراث، أليس هذا دليلًا قاطعًا على أن الإسلام يقيّم المرأة نصف قيمة الرجل؟"',
'تنتشر هذه الشبهة لأنها تستند لآية حقيقية موجودة فعلًا في القرآن، لكنها تُقرأ غالبًا بمعزل عن السياق الفقهي الأوسع لتوزيع المسؤوليات المالية بين الرجل والمرأة في الأسرة الإسلامية.',
'قاعدة "للذكر مثل حظ الأنثيين" ليست قاعدة عامة مطلقة في كل حالات الميراث (فهناك حالات ترث فيها المرأة مثل الرجل تمامًا أو أكثر منه بحسب درجة القرابة)، وحين تنطبق، فهي مرتبطة بتوزيع مختلف تمامًا للأعباء المالية: الرجل مُلزَم شرعًا بالإنفاق الكامل على زوجته وأولاده من ماله الخاص، بينما مال المرأة (ميراثها ومهرها وأجرها إن عملت) ملكها الخاص الكامل لا يُلزَم أحد بأخذ شيء منه.',
'من المهم أولًا تصحيح افتراض شائع: قاعدة "للذكر مثل حظ الأنثيين" ليست قاعدة الميراث الوحيدة أو المطلقة في الفقه الإسلامي؛ هناك حالات ميراث متعددة (تُذكَر تفصيلًا في علم الفرائض) ترث فيها المرأة مثل الرجل تمامًا، بل وحالات ترث فيها أكثر منه بحسب درجة قرابتها للمتوفى ووجود ورثة آخرين من عدمه. حين تنطبق قاعدة الضعف تحديدًا (كميراث الأخ والأخت الشقيقين مثلًا)، فإن السبب الفقهي المعلَن ليس تقييم قيمة إنسانية متفاوتة بين الجنسين، بل توزيعًا مختلفًا تمامًا للمسؤولية المالية داخل الأسرة: يُلزَم الرجل شرعًا بالإنفاق الكامل على زوجته وأولاده ومسكنهم من ماله الخاص، بينما ميراث المرأة ومهرها وأي مال تكسبه من عملها يبقى ملكها الشخصي الكامل، لا يُطالَب بأخذ جزء منه لنفقة أحد، حتى لو كانت غنية وزوجها فقيرًا نسبيًا. فحين يرث الأخ ضعف أخته مثلًا، فهو يتحمّل لاحقًا التزامًا ماليًا مضاعفًا فعليًا (نفقة أسرته الكاملة) لم تُلزَم به أختها إطلاقًا. هذا لا يعني أن كل تفصيلة في نظام الميراث خالية من نقاش فقهي مشروع حول تطبيقاتها المعاصرة، لكنه يصحح الافتراض الشائع الخاطئ بأن القاعدة تعني تقييمًا أدنى لقيمة المرأة الإنسانية.',
'مغالطة شائعة: قراءة قاعدة "للذكر مثل حظ الأنثيين" بمعزل تام عن الالتزام المالي المقابل المفروض على الرجل شرعًا، وكأن الميراث معيار وحيد منفصل لتقييم المساواة الإنسانية.',
'علم الفرائض (توزيع الميراث) من أدق علوم الفقه الإسلامي وأكثرها تفصيلًا، ويتضمن عشرات الحالات المختلفة لا حالة واحدة مكرَّرة، وقد أفرد له الفقهاء عبر التاريخ مصنَّفات مستقلة كاملة لدقّته.',
'[{"type":"quran","ref":"النساء: ٣٤","text":"الرِّجَالُ قَوَّامُونَ عَلَى النِّسَاءِ بِمَا فَضَّلَ اللَّهُ بَعْضَهُمْ عَلَىٰ بَعْضٍ وَبِمَا أَنفَقُوا مِنْ أَمْوَالِهِمْ"}]'::jsonb,
'[]'::jsonb,
'[{"objection":"ألا يمكن ببساطة مساواة الميراث والنفقة معًا بدل هذا التوزيع المعقّد؟","response":"هذا نقاش فقهي واجتماعي مشروع حول التطبيقات المعاصرة، يستحق تفصيلًا من عالم شرعي متخصص في مقاصد الشريعة، لا حسمًا مختصرًا هنا؛ لكن المهم توضيح أن النظام الأصلي ليس تعسفيًا أو مبنيًا على تقييم أدنى للمرأة كما يُظَن أحيانًا."}]'::jsonb,
'تفاوت أنصبة الميراث في بعض الحالات مرتبط بتوزيع مختلف للمسؤولية المالية الشرعية الملزمة، لا بتقييم متفاوت لقيمة الإنسان، وهذا سياق ضروري لفهم النظام بدقة بعيدًا عن الاختزال الشائع.',
'draft', false),

((SELECT id FROM dawah_categories WHERE slug='evil-suffering'), 'problem-of-evil-and-suffering-full',
'إذا كان الله رحيمًا قادرًا على كل شيء، فلماذا يوجد كل هذا الألم والمعاناة في العالم؟', 'advanced',
'"إن كان الله موجودًا وقادرًا وخيّرًا حقًا، فلماذا يسمح بمعاناة الأطفال والكوارث الطبيعية والظلم؟ أليس وجود الشر دليلًا على عدم وجود إله رحيم قادر، أو تناقضًا في صفاته؟"',
'هذه أعمق وأقدم شبهة فلسفية على الإطلاق ضد وجود إله رحيم قادر (مشكلة الشر الكلاسيكية)، تنتشر لأنها تلامس ألمًا إنسانيًا حقيقيًا يشعر به كل إنسان تقريبًا في مرحلة ما من حياته.',
'يفرّق الإسلام بين نوعين من الشر (الظلم الذي يسببه اختيار الإنسان الحر، والألم الطبيعي كالمرض والكوارث)، ويرى أن وجود حرية اختيار حقيقية للإنسان (شرط لازم لأي معنى أخلاقي حقيقي) يستلزم منطقيًا إمكان إساءة استخدامها، وأن الألم الطبيعي غير المفهوم كامل الحكمة من منظورنا المحدود لا يعني غيابها، مع وعد إلهي بعدل كامل تعويضي في الآخرة لا يفوت شيئًا.',
'أولًا، يميّز التصور الإسلامي بوضوح بين مصدرين مختلفين للشر: الظلم الذي يسببه اختيار الإنسان الحر (كالحروب والجرائم والاستغلال)، والألم الطبيعي غير الناتج عن اختيار بشري مباشر (كالأمراض والكوارث الطبيعية) — وكل نوع يحتاج معالجة مستقلة. بخصوص النوع الأول: يرى الإسلام أن منح الإنسان حرية اختيار حقيقية (شرط ضروري لأي معنى أخلاقي حقيقي أصلًا — فبلا حرية اختيار لا معنى للفضيلة أو الرذيلة أو الثواب والعقاب) يستلزم منطقيًا إمكان إساءة استخدام هذه الحرية، وهذا ليس عيبًا في التصميم الإلهي بل ثمن ضروري لوجود أخلاق حقيقية أصلًا؛ عالم بلا إمكانية اختيار الشر ليس عالمًا أخلاقيًا بل عالم دمى مبرمجة. بخصوص النوع الثاني (الألم الطبيعي): يقرّ الإسلام بصراحة بمحدودية فهمنا البشري لحكمة كل ألم فردي بعينه، لكنه يقدّم إطارًا يمنح الألم معنى محتملًا (كابتلاء يُصفّي النفس، أو تنبيه لضعف الإنسان يدفعه للتواضع والعودة لله، أو فرصة لظهور فضائل كالصبر والتراحم الإنساني التي لا تظهر إلا في وجود الألم أصلًا) دون الادعاء بمعرفة الحكمة التفصيلية الدقيقة لكل حالة بعينها. الأهم من ذلك: يعد الإسلام بعدل أخروي كامل تعويضي لا يفوت فيه أي ألم أو ظلم وقع في الدنيا مهما دقّ، وهذا يمنح المتألم رجاءً حقيقيًا لا وهميًا بأن معاناته ليست عبثية نهائية.',
'مغالطة شائعة: افتراض أن "الرحمة الإلهية" تعني بالضرورة منع كل ألم فورًا في كل لحظة، متجاهلة أن السماح المؤقت بالألم ضمن حكمة أوسع (كحرية الاختيار أو الابتلاء) لا يتناقض منطقيًا مع الرحمة الكاملة والقدرة المطلقة، بل قد يكون تعبيرًا عن حكمة أعمق لا نراها بكامل صورتها من منظورنا المحدود زمنيًا ومعرفيًا.',
'ناقش فلاسفة وعلماء كلام مسلمون هذه المسألة عبر قرون بعمق فلسفي حقيقي (لا تجاهلًا لها)، ولها نظائر فلسفية مشابهة في الفكر الديني اليهودي والمسيحي أيضًا تحت مسمى "Theodicy"، مما يدل على أنها سؤال إنساني عام لا خاص بالإسلام وحده.',
'[{"type":"quran","ref":"البقرة: ١٥٥-١٥٧","text":"وَلَنَبْلُوَنَّكُم بِشَيْءٍ مِّنَ الْخَوْفِ وَالْجُوعِ وَنَقْصٍ مِّنَ الْأَمْوَالِ وَالْأَنفُسِ وَالثَّمَرَاتِ ۗ وَبَشِّرِ الصَّابِرِينَ"}]'::jsonb,
'[]'::jsonb,
'[{"objection":"لماذا يعاني أطفال أبرياء لم يختاروا شيئًا أصلًا؟ لا ينطبق عليهم تفسير حرية الاختيار.","response":"هذا سؤال حقيقي وصعب يستحق تواضعًا فكريًا لا إجابة قاطعة متسرعة؛ يقدّم الإسلام إطار الابتلاء والتعويض الأخروي الكامل كرجاء حقيقي، مع إقرار صريح بمحدودية فهمنا البشري لكل حكمة تفصيلية، وهذا يستحق حوارًا مباشرًا أعمق مع داعية أو عالم متخصص لمن أراد تفصيلًا يراعي حالته الشخصية."}]'::jsonb,
'مشكلة الشر سؤال فلسفي عميق حقيقي لا يُختزَل في جملة دفاعية سريعة؛ يقدّم الإسلام إطارًا متماسكًا (حرية الاختيار، الابتلاء، العدل الأخروي الكامل) دون ادعاء إجابة تفصيلية نهائية عن كل حالة ألم فردية بعينها.',
'draft', false),

((SELECT id FROM dawah_categories WHERE slug='science-religion'), 'islam-and-evolution',
'هل يتعارض الإسلام مع نظرية التطور العلمية؟', 'advanced',
'"العلم الحديث يقرر أن الإنسان تطوّر عبر ملايين السنين من كائنات أبسط، بينما يقول الإسلام إن آدم خُلق مباشرة من طين، أليس هذا تناقضًا صريحًا بين الدين والعلم؟"',
'تنتشر هذه الشبهة لأنها تُقدَّم غالبًا كـ"إما/أو" حاسم بلا مساحة للتفصيل، بينما الموقف الإسلامي العلمي الجاد فيها أكثر تدرجًا وتنوعًا مما يُظَن.',
'يتفق علماء المسلمين على ثبات خلق آدم عليه السلام المباشر من طين كأصل نصي قرآني قطعي لا يقبل التأويل بما ينفيه، بينما تتفاوت اجتهاداتهم حول مدى انطباق نظرية التطور (كآلية علمية) على الكائنات الأخرى غير الإنسان أو على تفاصيل بيولوجية جزئية لم يرد فيها نص قاطع.',
'من الضروري أولًا التمييز بين مستويين مختلفين للنقاش: أولًا، أصل خلق آدم عليه السلام: يقرر القرآن نصًا صريحًا أن آدم خُلق مباشرة "من طين" وليس نتيجة تطور تدريجي عن كائن سابق، وهذا أصل عقدي قطعي عند جمهور علماء المسلمين المعتبرين لا يقبل التأويل بما ينفيه أو يُخضِعه لنظرية علمية بشرية قابلة للمراجعة أصلًا. ثانيًا، مسألة التطور كآلية بيولوجية عامة لتنوع الكائنات الأخرى (غير الإنسان تحديدًا): هنا يوجد تفاوت اجتهادي حقيقي وموثَّق بين علماء وباحثين مسلمين معاصرين؛ بعضهم يرى إمكان قبول آلية التطور كوصف علمي لكيفية تنوع الأنواع الأخرى ضمن خلق الله وتدبيره الشامل (فالتطور كآلية لا ينفي بالضرورة وجود خالق يدير هذه الآلية نفسها ويُوجّهها)، بينما يتحفّظ آخرون على قبولها كليًا لاعتبارات علمية أو نصية مختلفة. هذا التنوع الاجتهادي أمر معروف وموثَّق في الكتابات الإسلامية المعاصرة الجادة حول العلم والدين، لا موقفًا واحدًا جامدًا كما تصوّره الشبهة أحيانًا. من المهم أيضًا التمييز بين "نظرية التطور كعلم تجريبي قابل للمراجعة" و"الداروينية كفلسفة مادية شاملة تنفي وجود خالق أصلًا" — الإسلام يرفض الثانية بوضوح (نفي وجود خالق قصدي)، لكن قبول أو رفض الأولى كآلية علمية جزئية مسألة أكثر تفصيلًا وتحتاج نقاشًا علميًا-شرعيًا متخصصًا لا حسمًا مختصرًا هنا.',
'مغالطة شائعة: تقديم المسألة كـ"إما التطور بالكامل أو الخلق المباشر بالكامل لكل الكائنات دون استثناء" وكأن هذا الموقف الوحيد الممكن للمسلم، متجاهلة التمييز الضروري بين حالة آدم الخاصة القطعية النص وحالة الكائنات الأخرى الأقل قطعية نصيًا.',
'نقاش العلم والدين في الإسلام له تراث فكري طويل يمتد لعلماء مسلمين قدامى ناقشوا علاقة الوحي بالعلوم الطبيعية بعمق (كابن رشد وغيره)، وليس نقاشًا مستحدثًا فرضته المواجهة مع الداروينية الحديثة فقط.',
'[{"type":"quran","ref":"الحجر: ٢٦","text":"وَلَقَدْ خَلَقْنَا الْإِنسَانَ مِن صَلْصَالٍ مِّنْ حَمَإٍ مَّسْنُونٍ"}]'::jsonb,
'[]'::jsonb,
'[{"objection":"أليس هذا مجرد تلفيق بين نصوص قديمة ونظرية علمية حديثة؟","response":"لا، فالتمييز هنا دقيق ومحدود: القبول الجزئي المحتمل لآلية التطور في الكائنات الأخرى لا يمس أصل خلق آدم القطعي إطلاقًا عند القائلين به، وهو موقف اجتهادي معلن صراحة لا إخفاء فيه، ويستحق تفصيلًا أعمق من عالم متخصص في هذا الحوار تحديدًا لمن أراد ذلك."}]'::jsonb,
'موقف الإسلام من نظرية التطور أكثر تفصيلًا وتدرجًا مما تقدّمه الصورة الثنائية المختزلة الشائعة؛ خلق آدم المباشر أصل قطعي ثابت، بينما مسألة التطور كآلية علمية عامة لبقية الكائنات محل اجتهاد معتبر متنوع.',
'draft', false),

((SELECT id FROM dawah_categories WHERE slug='jihad'), 'meaning-of-jihad-general',
'ما معنى "الجهاد" فعليًا في الإسلام؟ هل يعني دائمًا الحرب؟', 'intermediate',
'"كلما سمعت كلمة جهاد أربطها تلقائيًا بالعنف والحرب المسلحة، هل هذا هو المعنى الحقيقي الوحيد للكلمة في الإسلام؟"',
'تنتشر هذه الشبهة لأن الاستخدام الإعلامي والسياسي المعاصر للكلمة، خصوصًا من جماعات متطرفة تُسيء استخدامها لتبرير عنف غير مشروع، اختزل المعنى الواسع الأصلي للكلمة في بُعدها العسكري الضيق حصرًا.',
'كلمة "جهاد" في اللغة العربية والاستخدام الشرعي الأصلي تعني "بذل الجهد" بمعنى واسع جدًا، وتشمل معاني متعددة أوسعها وأكثرها تكرارًا في النصوص هو "الجهاد الأكبر" (مجاهدة النفس والهوى)، بينما القتال المسلح المشروط بشروط صارمة جدًا هو أحد المعاني الفرعية الأضيق لا المعنى الحصري للكلمة.',
'كلمة "جهاد" في أصلها اللغوي العربي تعني ببساطة "بذل الجهد والطاقة" في سبيل تحقيق هدف، ولا ترتبط لغويًا بالحرب حصرًا إطلاقًا. في الاستخدام الشرعي الإسلامي، يُذكَر ما يُعرَف بـ"الجهاد الأكبر" (مجاهدة النفس والهوى والشيطان لضبط النفس على الاستقامة الأخلاقية اليومية) في أحاديث نبوية مشهورة كأعظم أنواع الجهاد وأكثرها إلحاحًا يوميًا لكل مسلم، وهو جهد أخلاقي داخلي مستمر لا علاقة له بالسلاح إطلاقًا. كذلك يشمل معنى الجهاد الدعوة السلمية للحق بالحجة والبيان ("وَجَاهِدْهُم بِهِ جِهَادًا كَبِيرًا" في سياق مجادلة بالقرآن لا بالسلاح)، والصبر على الأذى في سبيل المبدأ، وبذل الجهد في طلب العلم أو الإصلاح الاجتماعي. أما "الجهاد الأصغر" بمعنى القتال المسلح تحديدًا، فهو أحد المعاني الفرعية فقط، مقيَّد شرعًا بشروط صارمة جدًا (كإذن ولي أمر شرعي، وسياق دفاعي أو رد عدوان غالبًا، وضوابط أخلاقية صارمة حتى أثناء القتال نفسه كتحريم قتل غير المقاتلين)، لا معنى مطلقًا مفتوحًا لأي فرد يقرر استخدام العنف باجتهاده الشخصي كما تفعل الجماعات المتطرفة التي تسيء تمثيل هذا المفهوم إساءة بالغة. هذه التفصيلات الفقهية الدقيقة لضوابط القتال المشروع تستحق مادة مستقلة أعمق بمراجعة متخصصة نظرًا لحساسية الموضوع وسوء استخدامه المعاصر الواسع.',
'مغالطة شائعة: اختزال كلمة "جهاد" (ذات المعاني اللغوية والشرعية الواسعة جدًا) في معنى واحد ضيق هو "الحرب المسلحة غير المشروطة"، وهذا الاختزال بالذات هو ما تستغله الجماعات المتطرفة نفسها لتبرير عنفها، وتتبناه أيضًا صورة إعلامية سلبية مبسَّطة عن الإسلام دون قصد مماثل أحيانًا.',
'الاستخدام الإعلامي والسياسي المعاصر لكلمة "جهاد" (خصوصًا بعد أحداث عنف نُسِبت خطأً أو بحق لجماعات متطرفة) شكّل تصورًا شعبيًا ضيقًا جدًا للكلمة يختلف كثيرًا عن استخدامها الفقهي واللغوي التاريخي الأوسع عبر قرون من الأدب والفقه الإسلامي.',
'[{"type":"hadith","ref":"إسناده فيه مقال، مشهور عند أهل العلم بمعناه","grading":"يحتاج تحقق المراجع العلمي قبل الاعتماد على الدرجة بدقة","text":"رَجَعْنَا مِنَ الْجِهَادِ الْأَصْغَرِ إِلَى الْجِهَادِ الْأَكْبَرِ... مُجَاهَدَةُ الْعَبْدِ هَوَاهُ"}]'::jsonb,
'[]'::jsonb,
'[{"objection":"لماذا لا تفصّلون الشروط الفقهية الدقيقة للقتال المشروع هنا مباشرة؟","response":"تفصيل ضوابط القتال المشروع تحديدًا (شروطه، من يأذن به، حدوده) مسألة فقهية حساسة جدًا تستحق مادة مستقلة بتأليف متخصص دقيق نظرًا لخطورة سوء الفهم أو سوء الاستخدام، ونفضّل تأجيلها لمراجعة عالم شرعي متخصص بدل صياغة أولى مقتضبة هنا."}]'::jsonb,
'"الجهاد" مفهوم واسع جدًا في أصله اللغوي والشرعي، أوسع معانيه وأكثرها إلحاحًا يوميًا هو مجاهدة النفس لا القتال، والقتال المسلح فيه أحد أضيق معانيه الفرعية المقيَّدة بشروط صارمة، لا المعنى الحصري كما يُشاع.',
'draft', false),

((SELECT id FROM dawah_categories WHERE slug='relations-non-muslims'), 'islam-and-violence-perception',
'هل الإسلام دين عنيف بطبيعته كما تصوّره بعض وسائل الإعلام؟', 'advanced',
'"أرى أخبارًا كثيرة عن عنف يُرتكَب باسم الإسلام، هل هناك شيء في الدين نفسه يشجّع على العنف، أم أن هذا سوء استخدام من أفراد أو جماعات لا يمثّل الدين الحقيقي؟"',
'هذه من أكثر الشبهات إلحاحًا في العقود الأخيرة بسبب التغطية الإعلامية المكثفة لأحداث عنف ارتكبتها جماعات متطرفة نسبت نفسها للإسلام، مما خلق تصورًا شعبيًا واسعًا يربط الدين نفسه بالعنف بنيويًا.',
'الإسلام، كمصدر نصي وفقهي، يقيّد العنف بشروط صارمة جدًا ويُحرّم صراحة عنفًا واسعًا (قتل الأبرياء، الاعتداء، الإكراه في الدين)؛ الجماعات المتطرفة المعاصرة التي ترتكب عنفًا باسم الإسلام تخالف هذه الضوابط الفقهية المعتبرة نفسها مخالفة صريحة موثَّقة من علماء مسلمين معتبرين كُثر أدانوها بوضوح، لا تمثّلها.',
'من الأمانة الفكرية التمييز بدقة بين ثلاثة أمور مختلفة غالبًا ما تُخلَط: النصوص الإسلامية الأصلية نفسها، والفقه الإسلامي المعتبر عبر التاريخ، وسلوك أفراد أو جماعات معاصرة تنسب نفسها للإسلام. على مستوى النصوص والفقه المعتبر: يُحرّم الإسلام صراحة قتل النفس البريئة ("مَن قَتَلَ نَفْسًا بِغَيْرِ نَفْسٍ أَوْ فَسَادٍ فِي الْأَرْضِ فَكَأَنَّمَا قَتَلَ النَّاسَ جَمِيعًا")، ويُحرّم الإكراه في الدين نصًا ("لَا إِكْرَاهَ فِي الدِّينِ")، ويضع للقتال المشروع (حين يُشرَع أصلًا) شروطًا صارمة جدًا (إذن ولي أمر شرعي، سياق دفاعي غالبًا، تحريم قتل غير المقاتلين والنساء والأطفال وحتى الأشجار المثمرة في الحرب كما وصّى الخلفاء الراشدون جيوشهم). الجماعات المتطرفة المعاصرة التي ترتكب عنفًا عشوائيًا ضد مدنيين أبرياء، أو تُكفِّر مسلمين مخالفين، أو تفرض الدين قسرًا، تخالف هذه الضوابط الفقهية المعتبرة نفسها مخالفة صريحة، وقد أصدر علماء مسلمون معتبرون كُثر (وهيئات فقهية رسمية) بيانات وفتاوى واضحة تُدين هذا العنف وتنفي تمثيله للإسلام الصحيح. من المهم أيضًا وضع الأمر في سياقه الإحصائي الأوسع: الغالبية الساحقة من ضحايا هذه الجماعات المتطرفة تاريخيًا هم مسلمون أنفسهم، وهذا يناقض فرضية أن هذا العنف تعبير "طبيعي" عن جوهر الدين ذاته الذي يُفتَرَض أن يحمي أتباعه لا يستهدفهم. هذا لا يعني إنكار وجود نقاش فقهي وتاريخي حقيقي ومشروع حول تفسير بعض النصوص أو تطبيقات تاريخية معينة يستحق تناولًا علميًا جادًا، لا دفاعًا سطحيًا أو إنكارًا كليًا لكل نقاش.',
'مغالطة شائعة (تُعرَف منطقيًا بمغالطة "التعميم المتسرع"): الحكم على دين كامل يتبعه أكثر من مليار ونصف إنسان عبر سلوك أقلية متطرفة صغيرة جدًا نسبيًا، بدل الرجوع للمصدر النصي والفقهي المعتبر نفسه لتقييم الموقف الحقيقي.',
'التطرف العنيف باسم الدين ظاهرة موجودة تاريخيًا في أديان وأيديولوجيات متعددة غير الإسلام أيضًا (لا يخلو منها تاريخ ديني أو سياسي عالميًا)، وهذا لا يبرر عنف أي جماعة، لكنه يضع الظاهرة في سياقها الإنساني الأعم لا كخاصية إسلامية فريدة.',
'[{"type":"quran","ref":"المائدة: ٣٢","text":"مَن قَتَلَ نَفْسًا بِغَيْرِ نَفْسٍ أَوْ فَسَادٍ فِي الْأَرْضِ فَكَأَنَّمَا قَتَلَ النَّاسَ جَمِيعًا"}, {"type":"quran","ref":"البقرة: ٢٥٦","text":"لَا إِكْرَاهَ فِي الدِّينِ"}]'::jsonb,
'[]'::jsonb,
'[{"objection":"لكن هذه الجماعات تستشهد بآيات قرآنية فعلية لتبرير أفعالها، أليس هذا دليلًا على أن النص نفسه يحتمل هذا الفهم؟","response":"انتزاع آيات مفردة من سياقها التاريخي والنصي المباشر (وهو ما تفعله هذه الجماعات فعلًا) أسلوب تُمكِن به تحريف أي نص ديني أو حتى قانوني تقريبًا؛ الفهم الفقهي المعتبر المتراكم عبر قرون هو المرجع الصحيح لفهم النص لا اجتهاد فردي منعزل لجماعة متطرفة، وهذا موضوع مفصَّل في مادة مستقلة عن سياق آيات القتال تحديدًا."}]'::jsonb,
'العنف المرتكَب باسم الإسلام من جماعات متطرفة معاصرة يخالف الضوابط الفقهية الإسلامية المعتبرة نفسها مخالفة موثَّقة، ولا يمثّل الدين كمصدر نصي وفقهي، رغم استغلال هذه الجماعات لبعض نصوصه خارج سياقها.',
